 'use strict';document.addEventListener('DOMContentLoaded',()=>{initMobileMenu();initSmoothScroll();initActiveNav();initHeaderScroll();initCurrentYear();initAccessibility();initContactForm();});function initMobileMenu(){const menuToggle = document.querySelector('.menu-toggle');const navLinks = document.querySelector('.nav-links');const links = navLinks?.querySelectorAll('.nav-link');if(!menuToggle || !navLinks)return;menuToggle.addEventListener('click',()=>{const isExpanded = menuToggle.getAttribute('aria-expanded')=== 'true';menuToggle.setAttribute('aria-expanded',!isExpanded);navLinks.classList.toggle('active');document.body.style.overflow = isExpanded ? '':'hidden';});links?.forEach(link =>{link.addEventListener('click',()=>{menuToggle.setAttribute('aria-expanded','false');navLinks.classList.remove('active');document.body.style.overflow = '';});});const logo = document.querySelector('.logo');if(logo){logo.addEventListener('click',()=>{if(navLinks.classList.contains('active')){menuToggle.setAttribute('aria-expanded','false');navLinks.classList.remove('active');document.body.style.overflow = '';}});}document.addEventListener('keydown',(e)=>{if(e.key === 'Escape' && navLinks.classList.contains('active')){menuToggle.setAttribute('aria-expanded','false');navLinks.classList.remove('active');document.body.style.overflow = '';menuToggle.focus();}});document.addEventListener('click',(e)=>{if(!menuToggle.contains(e.target)&& !navLinks.contains(e.target)&& navLinks.classList.contains('active')){menuToggle.setAttribute('aria-expanded','false');navLinks.classList.remove('active');document.body.style.overflow = '';}});}function initSmoothScroll(){const links = document.querySelectorAll('a[href^="#"]');links.forEach(link =>{link.addEventListener('click',(e)=>{const href = link.getAttribute('href');if(href === '#' || href === '#0')return;const target = document.querySelector(href);if(!target)return;e.preventDefault();const headerHeight = document.querySelector('.header')?.offsetHeight || 0;const safePadding = 20;const targetPosition = target.getBoundingClientRect().top + window.pageYOffset - headerHeight - safePadding;window.scrollTo({top:targetPosition,behavior:'smooth'});history.pushState(null,'',href);target.setAttribute('tabindex','-1');target.focus({preventScroll:true});target.removeAttribute('tabindex');});});}function initActiveNav(){const sections = document.querySelectorAll('section[id]');const navLinks = document.querySelectorAll('.nav-link');if(sections.length === 0 || navLinks.length === 0)return;const observerOptions ={root:null,rootMargin:'-20% 0px -70% 0px',threshold:0};const observer = new IntersectionObserver((entries)=>{entries.forEach(entry =>{if(entry.isIntersecting){const id = entry.target.getAttribute('id');navLinks.forEach(link =>{link.classList.remove('active');if(link.getAttribute('href')=== `#${id}`){link.classList.add('active');}});}});},observerOptions);sections.forEach(section => observer.observe(section));}function initHeaderScroll(){const header = document.querySelector('.header');if(!header)return;let lastScrollY = window.pageYOffset;let ticking = false;const updateHeader =()=>{const scrollY = window.pageYOffset;if(scrollY > 100){header.style.boxShadow = '0 4px 6px rgba(0,0,0,0.04),0 2px 4px rgba(0,0,0,0.03)';}else{header.style.boxShadow = '0 1px 3px rgba(0,0,0,0.04),0 1px 2px rgba(0,0,0,0.02)';}lastScrollY = scrollY;ticking = false;};window.addEventListener('scroll',()=>{if(!ticking){window.requestAnimationFrame(updateHeader);ticking = true;}});}function initCurrentYear(){const yearElement = document.getElementById('current-year');if(yearElement){yearElement.textContent = new Date().getFullYear();}}function initAccessibility(){const interactiveCards = document.querySelectorAll('.feature-card,.step-card,.partner-logo');interactiveCards.forEach(card =>{card.addEventListener('keydown',(e)=>{if(e.key === 'Enter' || e.key === ' '){e.preventDefault();card.click();}});});const announcer = document.createElement('div');announcer.setAttribute('role','status');announcer.setAttribute('aria-live','polite');announcer.setAttribute('aria-atomic','true');announcer.className = 'sr-only';announcer.style.cssText = 'position:absolute;left:-10000px;width:1px;height:1px;overflow:hidden;';document.body.appendChild(announcer);window.qiyammAnnouncer =(message)=>{announcer.textContent = message;setTimeout(()=> announcer.textContent = '',1000);};document.addEventListener('keydown',(e)=>{if(e.key === 'Tab'){document.body.classList.add('keyboard-nav');}});document.addEventListener('mousedown',()=>{document.body.classList.remove('keyboard-nav');});}const style = document.createElement('style');style.textContent = ` .sr-only{position:absolute;left:-10000px;width:1px;height:1px;overflow:hidden;}body.keyboard-nav *:focus-visible{outline:2px solid #10B981;outline-offset:2px;border-radius:8px;}`;document.head.appendChild(style);function initContactForm(){const form = document.getElementById('contactForm');if(!form)return;form.addEventListener('submit',async(e)=>{e.preventDefault();const submitBtn = form.querySelector('button[type="submit"]');const btnText = submitBtn.querySelector('.btn-text');const btnLoader = submitBtn.querySelector('.btn-loader');const formMessage = document.getElementById('formMessage');submitBtn.disabled = true;btnText.style.display = 'none';btnLoader.style.display = 'flex';formMessage.style.display = 'none';const formData = new FormData(form);try{const response = await fetch('/contact',{method:'POST',body:formData,headers:{'X-Requested-With':'XMLHttpRequest','Accept':'application/json'}});const result = await response.json();if(response.ok){formMessage.textContent = result.message || 'تم إرسال رسالتك بنجاح! سنتواصل معك قريباً.';formMessage.className = 'form-message success';formMessage.style.display = 'block';form.reset();}else{formMessage.textContent = result.message || 'حدث خطأ أثناء إرسال الرسالة. يرجى المحاولة مرة أخرى.';formMessage.className = 'form-message error';formMessage.style.display = 'block';}}catch(error){formMessage.textContent = 'حدث خطأ في الاتصال. يرجى المحاولة لاحقاً.';formMessage.className = 'form-message error';formMessage.style.display = 'block';}finally{submitBtn.disabled = false;btnText.style.display = 'inline';btnLoader.style.display = 'none';}});const inputs = form.querySelectorAll('.form-input,.form-select,.form-textarea');inputs.forEach(input =>{input.addEventListener('blur',()=>{if(input.validity.valid){input.classList.remove('error');}else{input.classList.add('error');}});input.addEventListener('input',()=>{if(input.classList.contains('error')&& input.validity.valid){input.classList.remove('error');}});});}if('loading' in HTMLImageElement.prototype){const images = document.querySelectorAll('img[loading="lazy"]');images.forEach(img =>{img.src = img.dataset.src || img.src;});}window.addEventListener('error',(e)=>{});if(typeof module !== 'undefined' && module.exports){module.exports ={initMobileMenu,initSmoothScroll,initActiveNav,initHeaderScroll,initCurrentYear,initAccessibility,initContactForm};}